import logging
from typing import Dict, Type, Optional

import pkg_resources

from geosat.psanp.abstractions.stage import Stage

logger = logging.getLogger(__name__)


REGISTERED_STAGES: Dict[str, Type[Stage]] = {}


def register_stage(stage: Type[Stage]) -> None:
    """Add a Stage to the dict of registered Stages"""
    if stage.__name__ in REGISTERED_STAGES:
        raise KeyError(f"A stage named '{stage.__name__}' has already been registered")
    REGISTERED_STAGES[stage.__name__] = stage


def register_plugin_stages() -> None:
    plugins = {
        entry_point.name: entry_point.load()
        for entry_point in pkg_resources.iter_entry_points("psanp.plugins")
    }
    logger.info(f"Plugins loaded: {plugins}")


def get_stage(stage_name: str) -> Type[Stage]:
    if stage_name.endswith("Classifier"):
        return get_classifier(stage_name)
    return REGISTERED_STAGES[stage_name]


class UndefinedClassifierException(Exception):
    ...


def get_classifier(classifier_name: str) -> Type[Stage]:
    selected_classifier: str = ""
    selected_stage: Optional[Type[Stage]] = None
    for stage_name, stage in REGISTERED_STAGES.items():
        base_stage_name = stage_name.replace("Classifier", "")
        if classifier_name.startswith(base_stage_name):
            if selected_stage is None or len(selected_classifier) < len(
                base_stage_name
            ):
                selected_classifier = base_stage_name
                selected_stage = stage
    if selected_stage is not None:
        return selected_stage
    raise UndefinedClassifierException(
        f"The classifier {classifier_name} doesn't exist."
    )
